const row = $json;
const fields = ['Bot Update','Bug Fixed','Health Issue','Client Result','Lesson','Content Angle'];
const opsNote = fields.map(f => row[f]).filter(Boolean).join(' | ');
return [{ json: { ...row, ops_note_combined: opsNote || 'No ops note provided.' } }];

