const raw = $json.choices?.[0]?.message?.content || '{}';
let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = {
    linkedin_post: raw,
    x_post: '',
    youtube_idea: '',
    substack_idea: '',
    cta: 'Follow along for the build.'
  };
}
const source = $('Combine Ops Note Fields').first().json;
const today = new Date().toISOString().slice(0,10);
return [
  { json: { Date: today, Platform: 'LinkedIn', RawNote: source.ops_note_combined, FinalPost: parsed.linkedin_post || '', CTA: parsed.cta || '', Status: 'Draft', PostedLink: '' } },
  { json: { Date: today, Platform: 'X', RawNote: source.ops_note_combined, FinalPost: parsed.x_post || '', CTA: parsed.cta || '', Status: 'Draft', PostedLink: '' } },
  { json: { Date: today, Platform: 'YouTube', RawNote: source.ops_note_combined, FinalPost: parsed.youtube_idea || '', CTA: parsed.cta || '', Status: 'Draft', PostedLink: '' } },
  { json: { Date: today, Platform: 'Substack', RawNote: source.ops_note_combined, FinalPost: parsed.substack_idea || '', CTA: parsed.cta || '', Status: 'Draft', PostedLink: '' } }
];
